import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

function Navigation() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close menu on route change
  useEffect(() => {
    setMenuOpen(false);
  }, [location]);

  const navLinks = [
    { path: '/home', label: 'Home' },
    { path: '/about', label: 'About' },
    { path: '/portfolio', label: 'Portfolio' },
    { path: '/stories', label: 'Stories' },
    { path: '/services', label: 'Services' },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <>
      <nav className={`navigation ${scrolled ? 'scrolled' : ''} ${menuOpen ? 'menu-open' : ''}`}>
        <div className="nav-container">
          {/* Logo */}
          <Link to="/home" className="nav-logo" onClick={() => setMenuOpen(false)}>
            <span className="nav-logo-text">Jay Dabgar</span>
            <span className="nav-logo-line"></span>
            <span className="nav-logo-subtitle">Photography</span>
          </Link>

          {/* Desktop Navigation */}
          <ul className="nav-links-desktop">
            {navLinks.map((link) => (
              <li key={link.path}>
                <Link
                  to={link.path}
                  className={`nav-link ${isActive(link.path) ? 'active' : ''}`}
                >
                  {link.label}
                </Link>
              </li>
            ))}
            <li>
              <Link to="/contact" className="nav-link nav-cta">
                Contact
              </Link>
            </li>
          </ul>

          {/* Mobile Menu Button */}
          <button
            className={`hamburger ${menuOpen ? 'open' : ''}`}
            onClick={() => setMenuOpen(!menuOpen)}
            aria-label="Toggle menu"
            aria-expanded={menuOpen}
          >
            <span className="hamburger-line"></span>
            <span className="hamburger-line"></span>
            <span className="hamburger-line"></span>
          </button>
        </div>
      </nav>

      {/* Mobile Menu Overlay */}
      <div className={`mobile-menu ${menuOpen ? 'open' : ''}`}>
        <div className="mobile-menu-content">
          <ul className="mobile-nav-links">
            {navLinks.map((link, index) => (
              <li key={link.path} style={{ animationDelay: `${index * 0.1}s` }}>
                <Link
                  to={link.path}
                  className={`mobile-nav-link ${isActive(link.path) ? 'active' : ''}`}
                  onClick={() => setMenuOpen(false)}
                >
                  <span className="mobile-nav-number">0{index + 1}</span>
                  {link.label}
                </Link>
              </li>
            ))}
            <li style={{ animationDelay: '0.5s' }}>
              <Link
                to="/contact"
                className="mobile-nav-link mobile-nav-cta"
                onClick={() => setMenuOpen(false)}
              >
                <span className="mobile-nav-number">06</span>
                Contact
              </Link>
            </li>
          </ul>

          <div className="mobile-menu-footer">
            <p className="mobile-menu-tagline">Capturing Moments, Creating Stories</p>
            <div className="mobile-menu-social">
              <a href="#" aria-label="Instagram">IG</a>
              <a href="#" aria-label="Facebook">FB</a>
              <a href="#" aria-label="Pinterest">PN</a>
            </div>
          </div>
        </div>
      </div>

      {/* Overlay backdrop */}
      <div
        className={`nav-overlay ${menuOpen ? 'visible' : ''}`}
        onClick={() => setMenuOpen(false)}
      />
    </>
  );
}

export default Navigation;
